def es_primo(n):
    if n < 2:
        return False
    for i in range(2, int(n ** 0.5) + 1):
        if n % i == 0:
            return False
    return True

print(es_primo(7))
print(es_primo(9))

def potencia(base, exp):
    resultado = 1
    for _ in range(exp):
        resultado *= base
    return resultado

print(f'3 elevado a la 4 es: {potencia(3, 4)}')

def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)

print(f'6! = {factorial(6)}')

def fibonacci(n):
    if n == 0:
        return 0
    if n == 1:
        return 1
    return fibonacci(n - 1) + fibonacci(n - 2)

for i in range(8):
    print(fibonacci(i), end=' ')
