def calcular_media(lista):
    total = 0
    for n in lista:
        total += n
    return total / len(lista)

def calcular_minimo(lista):
    minimo = lista[0]
    for n in lista[1:]:
        if n < minimo:
            minimo = n
    return minimo

def calcular_maximo(lista):
    maximo = lista[0]
    for n in lista[1:]:
        if n > maximo:
            maximo = n
    return maximo

numeros = [4, 8, 2, 15, 6, 11, 3]
print(f'Media:   {calcular_media(numeros)}')
print(f'Mínimo:  {calcular_minimo(numeros)}')
print(f'Máximo:  {calcular_maximo(numeros)}')
